<script setup lang="ts">
import { computed,onBeforeUnmount,onMounted,reactive,ref } from 'vue';import{useI18n}from'vue-i18n';import{getConfig}from'@/api/admin';import{parseNonstream,startTest,testConnectivity}from'@/api/apiTest';import TestResponse from'@/components/TestResponse.vue';import{useTestStream}from'@/composables/useTestStream';import type{ConnectivityResult,TestRequest,TestResult}from'@/types/apiTest'
const{t}=useI18n();const form=reactive<TestRequest>({protocol:'openai',model:'',message:'Hello from the local API test.',stream:true,reasoning:true,reasoningEffort:'',taskType:'player_npc_dialogue',temperature:.7,maxTokens:4096});const loading=ref(true),busy=ref(false),connectivityBusy=ref(false),error=ref(''),result=ref<TestResult|null>(null),connectivity=ref<ConnectivityResult|null>(null),promptMode=ref('normal');const stream=useTestStream();let timer:number|undefined;const status=computed(()=>busy.value?t('apiTest.running'):result.value?t('apiTest.completeStatus'):t('apiTest.idle'))
async function load(){try{const config=await getConfig();form.model=config.defaultModel;form.protocol=config.upstreamProtocol==='ollama'?'ollama-chat':'openai';form.reasoning=config.forceReasoningEnabled;form.reasoningEffort=config.defaultReasoningEffort;promptMode.value=config.promptInjectionMode}catch(e){error.value=e instanceof Error?e.message:''}finally{loading.value=false}}
async function connectivityCheck(){if(connectivityBusy.value)return;connectivityBusy.value=true;error.value='';const controller=new globalThis.AbortController();stream.controller.value=controller;try{connectivity.value=await testConnectivity(controller.signal);if(connectivity.value.models.length&&!form.model)form.model=connectivity.value.models[0]!}catch(e){error.value=e instanceof Error?e.message:''}finally{connectivityBusy.value=false;if(stream.controller.value===controller)stream.controller.value=null}}
async function send(){if(busy.value)return;busy.value=true;stream.active.value=true;error.value='';result.value=null;const controller=new globalThis.AbortController();stream.controller.value=controller;timer=globalThis.window.setInterval(()=>{},1000);try{const started=await startTest(form,controller.signal);if(form.stream&&started.streamType)result.value=await stream.read(started.response,started.streamType,started.started,value=>result.value=value);else result.value=await parseNonstream(started.response,started.started,form.protocol)}catch(e){if((e as Error).name!=='AbortError')error.value=e instanceof Error?e.message:''}finally{if(timer!==undefined)globalThis.clearInterval(timer);timer=undefined;busy.value=false;stream.active.value=false;if(stream.controller.value===controller)stream.controller.value=null}}
function cancel(){stream.cancel();busy.value=false;if(timer!==undefined)globalThis.clearInterval(timer);timer=undefined}function clear(){result.value=null;error.value=''}async function copy(){if(result.value)await globalThis.navigator.clipboard.writeText(JSON.stringify(result.value.raw,null,2))}onMounted(load);onBeforeUnmount(cancel)
</script>
<template><section class="page api-test-page"><header class="page-heading"><div><p class="eyebrow">{{t('apiTest.eyebrow')}}</p><h1>{{t('apiTest.title')}}</h1></div><span>{{status}}</span></header><div v-if="loading" class="status-panel"><div class="status-dot"/><strong>{{t('apiTest.loading')}}</strong></div><template v-else><section class="form-section"><div class="section-heading"><h2>{{t('apiTest.connectivity')}}</h2><button type="button" :disabled="connectivityBusy" @click="connectivityCheck">{{connectivityBusy?t('apiTest.checking'):t('apiTest.check')}}</button></div><p v-if="connectivity">{{connectivity.protocol}} · {{connectivity.elapsedMs}} ms · {{connectivity.models.length}} {{t('apiTest.models')}}</p></section><form class="form-section" @submit.prevent="send"><div class="form-grid"><label>{{t('apiTest.protocol')}}<select v-model="form.protocol"><option value="openai">OpenAI</option><option value="ollama-chat">Ollama Chat</option><option value="ollama-generate">Ollama Generate</option></select></label><label>{{t('apiTest.model')}}<input v-model.trim="form.model" list="mock-models" required><datalist id="mock-models"><option v-for="model in connectivity?.models||[]" :key="model" :value="model"/></datalist></label><label>{{t('apiTest.temperature')}}<input v-model.number="form.temperature" type="number" min="0" max="2" step="0.1"></label><label>{{t('apiTest.maxTokens')}}<input v-model.number="form.maxTokens" type="number" min="1" max="32768"></label><label class="check"><input v-model="form.stream" type="checkbox">{{t('apiTest.streaming')}}</label><label class="check"><input v-model="form.reasoning" type="checkbox">{{t('apiTest.reasoningEnabled')}}</label><label>{{t('apiTest.effort')}}<select v-model="form.reasoningEffort"><option v-for="effort in ['','none','low','medium','high','max']" :key="effort" :value="effort">{{effort?t(`settings.efforts.${effort}`):t('apiTest.defaultEffort')}}</option></select></label><label>{{t('apiTest.task')}}<select v-model="form.taskType"><option value="player_npc_dialogue">{{t('apiTest.npcTask')}}</option><option value="dynamic_event_world_state">{{t('apiTest.systemTask')}}</option></select></label><label class="wide">{{t('apiTest.message')}}<textarea v-model="form.message" rows="5" required/></label></div><p>{{t('apiTest.promptMode')}}: {{t(`apiTest.mode_${promptMode}`)}}</p><div class="button-row"><button class="primary-button" type="submit" :disabled="busy">{{t('apiTest.send')}}</button><button type="button" :disabled="!busy" @click="cancel">{{t('apiTest.cancel')}}</button></div></form><TestResponse :result="result" :error="error" @clear="clear" @copy="copy"/></template></section></template>
